return kimenet;

// Használat: tedd ezt a CODE node végére (vagy egy külön Function/Code node-ba),
// ahol már elérhető az input JSON, amiben benne van az _execution_report.
// Nem használ Node env-et, nem olvas fájlt, nem require-ol modulokat.

function szamBiztonsagos(x) {
  const n = (typeof x === "number") ? x : Number(x);
  return Number.isFinite(n) ? n : null;
}

function kerek4(x) {
  const n = szamBiztonsagos(x);
  if (n === null) return null;
  return Math.round(n * 10000) / 10000;
}

function lepesKikeres(item, type) {
  const steps = (item && Array.isArray(item.steps)) ? item.steps : [];
  for (let i = 0; i < steps.length; i++) {
    const s = steps[i];
    if (s && s.type === type) return s;
  }
  return null;
}

function jeloltekNormalizalasaEsRendezese(allCandidates) {
  if (!Array.isArray(allCandidates)) return [];
  const out = [];
  for (let i = 0; i < allCandidates.length; i++) {
    const c = allCandidates[i] || {};
    const name = c.name != null ? String(c.name) : "";
    if (!name) continue;
    out.push({
      name: name,
      similarity: kerek4(c.similarity),
      alapszabaly: Boolean(c.alapszabaly)
    });
  }
  out.sort(function (a, b) {
    const as = (a.similarity == null) ? -1 : a.similarity;
    const bs = (b.similarity == null) ? -1 : b.similarity;
    return bs - as;
  });
  return out;
}

function itemEmberbarat(item, index) {
  const primary = lepesKikeres(item, "primary_search");
  const fallback = lepesKikeres(item, "fallback_search");
  const finalOutcome = (item && item.final_outcome) ? item.final_outcome : {};
  const status = finalOutcome.status || "UNKNOWN";

  const primaryHit = primary && primary.status === "HIT";
  const fallbackHit = fallback && fallback.status === "HIT";

  const primaryOverride = primary ? Boolean(primary.alapszabaly_override) : false;

  let valasztasModja = "nincs_talalat";
  if (status === "MATCHED") {
    if (primaryOverride) valasztasModja = "primary_custom_override";
    else if (primaryHit) valasztasModja = "primary";
    else if (fallbackHit) valasztasModja = "fallback";
    else valasztasModja = "ismeretlen_match_ut";
  }

  const primaryCandidates = primary ? jeloltekNormalizalasaEsRendezese(primary.all_candidates) : [];

  const primaryChosenName = primaryHit ? (primary.candidate_name || null) : null;
  const primaryChosenSim = primaryHit ? kerek4(primary.similarity) : null;
  const primaryThreshold = primary && primary.threshold != null ? kerek4(primary.threshold) : null;

  const fallbackChosenName = fallbackHit ? (fallback.candidate_name || null) : null;
  const fallbackChosenSim = fallbackHit ? kerek4(fallback.similarity) : null;
  const fallbackThreshold = fallback && fallback.threshold != null ? kerek4(fallback.threshold) : null;

  const miAlapjan = (function () {
    if (status !== "MATCHED") {
      const pr = (primary && primary.reason) ? ("Primary: " + primary.reason) : "Primary: MISS";
      const fb = (fallback && fallback.reason) ? ("Fallback: " + fallback.reason) : "Fallback: MISS";
      return pr + "; " + fb;
    }

    if (valasztasModja === "primary_custom_override") {
      const base = primaryChosenName ? ("Override, kiválasztva: " + primaryChosenName) : "Override";
      const sim = (primaryChosenSim != null) ? (" (sim=" + primaryChosenSim + ")") : "";
      return base + sim;
    }

    if (valasztasModja === "primary") {
      const base = primaryChosenName ? ("Primary, kiválasztva: " + primaryChosenName) : "Primary";
      const sim = (primaryChosenSim != null) ? (" (sim=" + primaryChosenSim + ")") : "";
      const thr = (primaryThreshold != null) ? (", küszöb=" + primaryThreshold) : "";
      return base + sim + thr;
    }

    if (valasztasModja === "fallback") {
      const base = fallbackChosenName ? ("Fallback, kiválasztva: " + fallbackChosenName) : "Fallback";
      const sim = (fallbackChosenSim != null) ? (" (sim=" + fallbackChosenSim + ")") : "";
      const thr = (fallbackThreshold != null) ? (", küszöb=" + fallbackThreshold) : "";
      return base + sim + thr;
    }

    return "MATCHED (ismeretlen döntési út)";
  })();

  return {
    sorszam: index + 1,
    id: item ? (item.id || null) : null,
    input_text: item ? (item.input_text || null) : null,
    context_text: item ? (item.context_text || null) : null,

    eredmeny: {
      status: status,
      rule_name: finalOutcome.rule_name || null,
      rule_id: finalOutcome.rule_id || null,
      alapszabaly: (finalOutcome.alapszabaly == null) ? null : Boolean(finalOutcome.alapszabaly),
      valasztas_modja: valasztasModja,
      mi_alapjan: miAlapjan
    },

    keresek: {
      primary: {
        status: primary ? (primary.status || "N/A") : "N/A",
        threshold: primaryThreshold,
        kivalasztott: primaryHit ? {
          name: primaryChosenName,
          similarity: primaryChosenSim,
          alapszabaly_override: primaryOverride
        } : null,
        jeloltek: primaryCandidates.length ? primaryCandidates : null
      },
      fallback: {
        status: fallback ? (fallback.status || "N/A") : "N/A",
        threshold: fallbackThreshold,
        kivalasztott: fallbackHit ? {
          name: fallbackChosenName,
          similarity: fallbackChosenSim
        } : null
      }
    }
  };
}

function statEmberbarat(stats, items) {
  const total = (stats && stats.total != null) ? szamBiztonsagos(stats.total) : (Array.isArray(items) ? items.length : null);
  const matched = (stats && stats.matched != null) ? szamBiztonsagos(stats.matched) : null;
  const matchRate = (stats && stats.match_rate != null) ? String(stats.match_rate) : null;

  const sims = [];
  for (let i = 0; i < items.length; i++) {
    const it = items[i] || {};
    const p = it.keresek && it.keresek.primary && it.keresek.primary.kivalasztott ? it.keresek.primary.kivalasztott.similarity : null;
    const f = it.keresek && it.keresek.fallback && it.keresek.fallback.kivalasztott ? it.keresek.fallback.kivalasztott.similarity : null;
    const v = (typeof p === "number") ? p : ((typeof f === "number") ? f : null);
    if (v != null && Number.isFinite(v)) sims.push(v);
  }

  sims.sort(function (a, b) { return a - b; });

  let atlag = null;
  if (sims.length) {
    let sum = 0;
    for (let i = 0; i < sims.length; i++) sum += sims[i];
    atlag = sum / sims.length;
  }

  let median = null;
  if (sims.length) {
    const mid = Math.floor(sims.length / 2);
    if (sims.length % 2 === 1) median = sims[mid];
    else median = (sims[mid - 1] + sims[mid]) / 2;
  }

  return {
    total: total,
    matched: matched,
    match_rate: matchRate,
    similarity_osszesites: {
      darab: sims.length,
      atlag: atlag == null ? null : kerek4(atlag),
      median: median == null ? null : kerek4(median),
      min: sims.length ? kerek4(sims[0]) : null,
      max: sims.length ? kerek4(sims[sims.length - 1]) : null
    }
  };
}

function emberbaratJelentesKeszites(input) {
  const exec = (input && Array.isArray(input._execution_report)) ? input._execution_report : [];
  const items = [];
  for (let i = 0; i < exec.length; i++) {
    items.push(itemEmberbarat(exec[i], i));
  }

  return {
    meta: {
      generator: "execution_report -> emberbarat_json",
      created_at: new Date().toISOString()
    },
    statisztika: statEmberbarat(input ? input._semantic_match_stats : null, items),
    talalatok: items
  };
}

// -------------------- RUN --------------------
// n8n kompatibilis: $input.first().json -> bemenet
