  };
} catch (e) {
  transcriberObj = { text: null, raw: null };
}

// 3) execution report human az aktuális itemből
const executionReportHuman = input._execution_report_human ?? null;

// EGY OBJECT, amire hivatkozni tudsz
const payload = {
  szoveges_lista: szovegesLista,
  transcriber: transcriberObj,
  execution_report_human: executionReportHuman
};

// Ha azt akarod, hogy tényleg csak ez menjen tovább, és semmi más:
return [{ json: { payload } }];

